const tasks = [
  { id: 1, text: 'Buy milk',   done: false },
  { id: 2, text: 'Write docs', done: true  },
  { id: 3, text: 'Fix bug',    done: false },
];

function ActiveTasks({ tasks }) {
  const active = tasks.filter(t => !t.done);

  return (
    <ul>
      {active.map(t => (
        <li key={t.id}>{t.text}</li>
      ))}
    </ul>
  );
}

// ✗ Mutates state — React won't always re-render correctly
function BadList({ items }) {
  items.sort((a, b) => a.name.localeCompare(b.name)); // mutation!
  return items.map(i => <li key={i.id}>{i.name}</li>);
}

// ✓ Spread to create a new array before sorting
function GoodList({ items }) {
  const sorted = [...items].sort((a, b) => a.name.localeCompare(b.name));
  return (
    <ul>
      {sorted.map(i => <li key={i.id}>{i.name}</li>)}
    </ul>
  );
}

// Ascending price
const byPrice = [...products].sort((a, b) => a.price - b.price);

// Descending price
const byPriceDesc = [...products].sort((a, b) => b.price - a.price);

// Date sort (ISO strings compare correctly as strings)
const byDate = [...posts].sort((a, b) =>
