);

function ScoreBoard({ players }) {
  return (
    <ol>
      {players
        .filter(p => p.active)          // 1. only active players
        .sort((a, b) => b.score - a.score) // 2. highest score first
        .map(p => (                      // 3. JSX per player
          <li key={p.id}>
            {p.name} — {p.score} pts
          </li>
        ))}
    </ol>
  );
}

function UserDirectory({ users, filterText, sortBy }) {
  const visible = users
    .filter(u =>
      u.name.toLowerCase().includes(filterText.toLowerCase())
    )
    .sort((a, b) => {
      if (sortBy === 'name') return a.name.localeCompare(b.name);
      if (sortBy === 'joined') return new Date(a.joined) - new Date(b.joined);
      return 0;
    });

  if (visible.length === 0) {
    return <p>No users match "{filterText}".</p>;
  }

  return (
    <>
      <p>{visible.length} result(s)</p>
      <ul>
        {visible.map(u => (
          <li key={u.id}>{u.name}</li>
        ))}
      </ul>
    </>
  );
}

function ProductList({ products, category, maxPrice, inStockOnly }) {
  const visible = products.filter(p =>
    (category === 'all' || p.category === category) &&
    p.price <= maxPrice &&
    (!inStockOnly || p.stock > 0)
  );

  return (
    <ul>
      {visible.map(p => (
        <li key={p.id}>
          {p.name} — ${p.price}
        </li>
      ))}
    </ul>
  );
}

// ✗ ASCII comparison — breaks for 'café', 'naïve', etc.
const bad = [...names].sort((a, b) => (a > b ? 1 : -1));

// ✓ Locale-aware, handles accents, case-insensitive option
const good = [...names].sort((a, b) =>
  a.localeCompare(b, undefined, { sensitivity: 'base' })
);
// 'base' sensitivity: a=A=à=À (accent+case insensitive)

function SortableTable({ rows }) {
  const [col, setCol] = useState('name');
  const [dir, setDir] = useState(1); // 1 = asc, -1 = desc

  function toggleSort(column) {
    if (col === column) {
      setDir(d => -d);  // flip direction
    } else {
      setCol(column);
      setDir(1);        // reset to ascending for new column
    }
  }

  const sorted = [...rows].sort((a, b) => {
    const cmp = typeof a[col] === 'string'
      ? a[col].localeCompare(b[col])
      : a[col] - b[col];
    return cmp * dir;
  });

  return (
    <table>
      <thead>
        <tr>
          <th onClick={() => toggleSort('name')}>Name</th>
          <th onClick={() => toggleSort('score')}>Score</th>
        </tr>
      </thead>
      <tbody>
        {sorted.map(r => (
          <tr key={r.id}>
            <td>{r.name}</td>
            <td>{r.score}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

import { useMemo } from 'react';

function ProductGrid({ products, search, sort }) {
  const visible = useMemo(() =>
    products
      .filter(p => p.name.toLowerCase().includes(search.toLowerCase()))
      .sort((a, b) => (sort === 'price' ? a.price - b.price
                     : a.name.localeCompare(b.name))),
    [products, search, sort]  // only recomputes when these change
  );

  return (
    <ul>
      {visible.map(p => (
        <li key={p.id}>{p.name} — ${p.price}</li>
      ))}
    </ul>
  );
}

