function FilteredList({ items, query }) {
  const results = items.filter(i =>
    i.title.toLowerCase().includes(query.toLowerCase())
  );

  if (results.length === 0) {
    return <p>No items match "{query}".</p>;
  }

  return (
    <ul>
      {results.map(i => <li key={i.id}>{i.title}</li>)}
    </ul>
  );
}

import { useState } from 'react';

const FRUITS = [
  { id: 1, name: 'Apple' },
  { id: 2, name: 'Banana' },
  { id: 3, name: 'Blueberry' },
  { id: 4, name: 'Cherry' },
  { id: 5, name: 'Avocado' },
];

export function FruitSearch() {
  const [query, setQuery] = useState('');

  const visible = FRUITS.filter(f =>
    f.name.toLowerCase().startsWith(query.toLowerCase())
  );

  return (
    <div>
      <input
        type="search"
        value={query}
        onChange={e => setQuery(e.target.value)}
        placeholder="Search fruits…"
      />
      <ul>
        {visible.map(f => <li key={f.id}>{f.name}</li>)}
      </ul>
      {visible.length === 0 && <p>No match for "{query}".</p>}
    </div>
  );
}

