type Item = { id: number; status: 'active' | 'archived' };

// Without predicate: TypeScript keeps Item[]
const active1 = items.filter(i => i.status === 'active');
// active1: Item[]

// With type predicate: TypeScript narrows to ActiveItem[]
type ActiveItem = { id: number; status: 'active' };
const active2 = items.filter(
  (i): i is ActiveItem => i.status === 'active'
);
// active2: ActiveItem[]

import { useState, useMemo } from 'react';

const CONTACTS = [
  { id: 1, name: 'Alice Chen',   dept: 'Engineering', active: true  },
  { id: 2, name: 'Bob Smith',    dept: 'Design',       active: true  },
  { id: 3, name: 'Carol Park',   dept: 'Engineering', active: false },
  { id: 4, name: 'Dave Torres',  dept: 'Design',       active: true  },
  { id: 5, name: 'Eve Johnson',  dept: 'Engineering', active: true  },
];

export function ContactsDirectory() {
  const [search, setSearch]     = useState('');
  const [dept, setDept]         = useState('all');
  const [showActive, setActive] = useState(true);

  const visible = useMemo(() =>
    CONTACTS
      .filter(c =>
        c.name.toLowerCase().includes(search.toLowerCase()) &&
        (dept === 'all' || c.dept === dept) &&
        (!showActive || c.active)
      )
      .sort((a, b) => a.name.localeCompare(b.name)),
    [search, dept, showActive]
  );

  return (
    <div>
      <input
        value={search}
        onChange={e => setSearch(e.target.value)}
        placeholder="Search…"
      />
      <select value={dept} onChange={e => setDept(e.target.value)}>
        <option value="all">All depts</option>
        <option value="Engineering">Engineering</option>
        <option value="Design">Design</option>
      </select>
      <label>
        <input
          type="checkbox"
          checked={showActive}
          onChange={e => setActive(e.target.checked)}
        />
        Active only
      </label>
      <p>{visible.length} contact(s)</p>
      <ul>
        {visible.map(c => (
          <li key={c.id}>
            {c.name} — {c.dept}
          </li>
        ))}
      </ul>
    </div>
  );
}

import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { FruitSearch } from './FruitSearch';

test('shows all items initially', () => {
  render(<FruitSearch />);
  expect(screen.getAllByRole('listitem')).toHaveLength(5);
});

test('filters by search query', async () => {
  render(<FruitSearch />);
  await userEvent.type(screen.getByRole('searchbox'), 'b');
  const items = screen.getAllByRole('listitem');
  expect(items).toHaveLength(2); // Banana, Blueberry
  expect(items[0]).toHaveTextContent('Banana');
  expect(items[1]).toHaveTextContent('Blueberry');
});

test('shows empty message when no match', async () => {
  render(<FruitSearch />);
  await userEvent.type(screen.getByRole('searchbox'), 'xyz');
  expect(screen.queryAllByRole('listitem')).toHaveLength(0);
  expect(screen.getByText(/No match for/)).toBeInTheDocument();
});
